arguments.new_str:
using System.Net.Http;
using System.Windows.Forms;
class ImageLoader
{
    void LoadImage(PictureBox pictureBox, string url)
    {
        // .NET 9: PictureBox.Load now uses HttpClient instead of WebClient,
        // so network errors throw HttpRequestException instead of WebException.
        try { pictureBox.Load(url); }
        catch (HttpRequestException ex) { Console.WriteLine("Failed: " + ex.Message); }
    }
}

